    lines.append("────────────")
    lines.append("⏳ <b>진행중</b>")
    for rec, st, pnl, cur in active[-5:]:
        lines.append(f"• {rec['symbol']} | 현재 {pnl:+.2f}% | 목표 {rec.get('target1')} | 손절 {rec.get('stop')}")
