# ===== A100 v45.1 Single Polling / Render Restart Fix =====
# - deleteWebhook 자동 실행
# - drop_pending_updates 적용
# - 같은 컨테이너 내 중복 실행 방지 lock
# - Render 배포 중 구/신 인스턴스 중첩 시 Conflict 자동 재시도
# - 하나의 asyncio event loop에서 Telegram polling 실행

V44_RETRY_MIN = int(os.getenv("V44_RETRY_MIN", "5"))
V44_RETRY_MAX = int(os.getenv("V44_RETRY_MAX", "60"))
V44_LOCK_FILE = os.getenv("V44_LOCK_FILE", "/tmp/a100_telegram_polling.lock")
_V44_LOCK_HANDLE = None

def acquire_v44_process_lock():
    """같은 컨테이너 안에서 main.py가 두 번 실행되는 것을 방지."""
    global _V44_LOCK_HANDLE
    try:
        import fcntl
        _V44_LOCK_HANDLE = open(V44_LOCK_FILE, "w", encoding="utf-8")
        fcntl.flock(_V44_LOCK_HANDLE.fileno(), fcntl.LOCK_EX | fcntl.LOCK_NB)
        _V44_LOCK_HANDLE.write(str(os.getpid()))
        _V44_LOCK_HANDLE.flush()
        return True
    except BlockingIOError:
        print("A100 v45.1: another polling process already owns the local lock", flush=True)
        return False
    except Exception as e:
        # Render/Linux 외 환경에서는 lock 실패로 봇 전체를 막지 않음
        print(f"A100 v45.1 lock warning: {e}", flush=True)
        return True


# ===== A100 v45.1.1 Region Guard =====
V45_BINANCE_TIMEOUT=float(os.getenv("V45_BINANCE_TIMEOUT","7"))
V45_CG_TIMEOUT=float(os.getenv("V45_CG_TIMEOUT","10"))
V45_CG_TTL=int(os.getenv("V45_CG_TTL","900"))
V45_BINANCE_TTL=int(os.getenv("V45_BINANCE_TTL","30"))
V45_CG_COOLDOWN=int(os.getenv("V45_CG_COOLDOWN","900"))
BINANCE_FUTURES_HOSTS=["https://fapi.binance.com","https://fapi1.binance.com","https://fapi2.binance.com","https://fapi3.binance.com"]
V45_API_STATE={
 "binance":{"ts":0,"ticker":[],"exchange_info":{},"host":"","err":"","latency_ms":None},
 "coinglass":{"ts":0,"err":"","latency_ms":None,"cooldown_until":0}
}
V45_CG_CACHE={}
V45_SESSION=requests.Session()
V45_SESSION.headers.update({"User-Agent":"Mozilla/5.0 A100Bot/45","Accept":"application/json,text/plain,*/*","Connection":"keep-alive"})
V45_CG_LOCK=threading.RLock()
V45_CG_LAST_CALL=0.0
V45_CG_MIN_INTERVAL=float(os.getenv("V45_CG_MIN_INTERVAL","0.35"))


def v45_get_json(url,params=None,headers=None,timeout=7):
    t0=time.time()
    r=V45_SESSION.get(url,params=params or {},headers=headers or {},timeout=timeout)
    latency=int((time.time()-t0)*1000)
    try:data=r.json()
    except Exception:data=None
    return r.status_code,data,latency,getattr(r,"text","")[:300]

def v45_binance_futures_refresh(force=False):
    st=V45_API_STATE["binance"]
    if not force and st["ticker"] and now_ts()-st["ts"]<=V45_BINANCE_TTL:return st
    last_err=""
    for host in BINANCE_FUTURES_HOSTS:
        try:
            c1,ticker,l1,x1=v45_get_json(host+"/fapi/v1/ticker/24hr",timeout=V45_BINANCE_TIMEOUT)
            c2,exinfo,l2,x2=v45_get_json(host+"/fapi/v1/exchangeInfo",timeout=V45_BINANCE_TIMEOUT)
            if c1==200 and isinstance(ticker,list) and c2==200 and isinstance(exinfo,dict):
                st.update({"ts":now_ts(),"ticker":ticker,"exchange_info":exinfo,"host":host,"err":"","latency_ms":l1+l2})
                return st
            last_err=f"{host} ticker={c1} exchangeInfo={c2} {x1[:60]} {x2[:60]}"
        except Exception as e:last_err=f"{host}: {e}"
    st["err"]=last_err or "Binance Futures unavailable"
    return st

def v45_binance_symbols():
    st=v45_binance_futures_refresh()
    out=[]
    for s in (st.get("exchange_info") or {}).get("symbols",[]):
        if s.get("quoteAsset")=="USDT" and s.get("contractType")=="PERPETUAL" and s.get("status")=="TRADING":
            out.append(s.get("symbol"))
    return out

def v45_binance_market(symbol="BTCUSDT"):
    st=v45_binance_futures_refresh()
    host=st.get("host") or BINANCE_FUTURES_HOSTS[0]
    out={"funding":None,"oi":None,"ticker":None,"errors":[]}
    for name,path in [("funding","/fapi/v1/premiumIndex"),("oi","/fapi/v1/openInterest"),("ticker","/fapi/v1/ticker/24hr")]:
        try:
            code,data,_,text=v45_get_json(host+path,params={"symbol":symbol},timeout=V45_BINANCE_TIMEOUT)
            if code==200 and isinstance(data,dict):
                if name=="funding":out[name]=float(data.get("lastFundingRate"))
                elif name=="oi":out[name]=float(data.get("openInterest"))
                else:out[name]=data
            else:out["errors"].append(f"{name} {code}: {text[:90]}")
        except Exception as e:out["errors"].append(f"{name}: {e}")
    return out

def v45_cg_headers():
    key=os.getenv("COINGLASS_API_KEY") or os.getenv("CG_API_KEY") or ""
    return {"CG-API-KEY":key} if key else {}

def v45_cg_request(path,params=None,cache_key=None,force=False):
    global V45_CG_LAST_CALL
    now=now_ts(); st=V45_API_STATE["coinglass"]
    if not v45_cg_headers():return {"ok":False,"status":None,"data":None,"err":"API key missing","latency_ms":None}
    ck=cache_key or f"{path}:{sorted((params or {}).items())}"
    c=V45_CG_CACHE.get(ck)
    if c and not force and now-c["ts"]<=V45_CG_TTL:return c["value"]
    if now<st.get("cooldown_until",0):
        if c:return dict(c["value"],stale=True,err="CoinGlass cooldown - stale cache")
        return {"ok":False,"status":429,"data":None,"err":"CoinGlass cooldown active","latency_ms":None}
    try:
        with V45_CG_LOCK:
            wait=V45_CG_MIN_INTERVAL-(time.time()-V45_CG_LAST_CALL)
            if wait>0:time.sleep(wait)
            code,payload,lat,text=v45_get_json("https://open-api-v4.coinglass.com"+path,params=params,headers=v45_cg_headers(),timeout=V45_CG_TIMEOUT)
            V45_CG_LAST_CALL=time.time()
        pcode=str(payload.get("code")) if isinstance(payload,dict) else ""
        if code==429 or pcode=="429":
            st["cooldown_until"]=now+V45_CG_COOLDOWN
            if c:val=dict(c["value"],stale=True,err="Too Many Requests - stale cache")
            else:val={"ok":False,"status":429,"data":None,"err":"Too Many Requests","latency_ms":lat}
        elif code!=200 or not isinstance(payload,dict):
            if c:val=dict(c["value"],stale=True,err=f"HTTP {code} - stale cache")
            else:val={"ok":False,"status":code,"data":None,"err":text[:180],"latency_ms":lat}
        elif pcode not in ("0","200"):
            if c:val=dict(c["value"],stale=True,err=str(payload.get("msg","API error"))[:100]+" - stale cache")
            else:val={"ok":False,"status":code,"data":None,"err":str(payload.get("msg",payload))[:180],"latency_ms":lat}
        else:
            val={"ok":True,"status":code,"data":payload.get("data"),"err":"","latency_ms":lat,"stale":False}
            V45_CG_CACHE[ck]={"ts":now,"value":val}
        st.update({"ts":now,"latency_ms":lat,"err":val.get("err","")})
        return val
    except Exception as e:
        st["err"]=str(e)
        if c:return dict(c["value"],stale=True,err=str(e)+" - stale cache")
        return {"ok":False,"status":None,"data":None,"err":str(e),"latency_ms":None}

def v45_cg_supported(force=False):
    return v45_cg_request("/api/futures/supported-coins",cache_key="supported",force=force)

def _cg_request_variants(name, coin, variants, force=False):
    """Startup 플랜 호환 파라미터를 순차 시도한다.
    플랜/interval 제한은 다음 후보로 자동 폴백하며 성공한 조합을 캐시한다.
    """
    errors=[]
    for idx,(path,params) in enumerate(variants):
        key=f"v47:{name}:{coin}:{idx}:{sorted(params.items())}"
        r=v45_cg_request(path,params=params,cache_key=key,force=force)
        if r.get("ok") and r.get("data") not in (None,[],{}):
            return r.get("data"), {"ok":True,"path":path,"params":params,"stale":r.get("stale",False)}
        errors.append(r.get("err") or f"HTTP {r.get('status')}")
    return None, {"ok":False,"errors":errors}

def v45_cg_coin(symbol="BTC",force=False):
    """A100 v47 CoinGlass Startup collector.

    History endpoint의 interval 제한에 의존하지 않고, 우선 exchange-list/range
    엔드포인트를 사용한다. History가 필요한 항목은 4h→1h→1d 순으로 폴백한다.
    """
    coin=symbol.upper().replace("USDT","")
    pair=coin+"USDT"
    out={"oi":None,"funding":None,"taker":None,"ls":None,"liquidation":None,
         "top_account":None,"top_position":None,"basis":None,
         "errors":{},"meta":{}}

    specs={
      "oi":[
        ("/api/futures/open-interest/exchange-list",{"symbol":coin}),
      ],
      "funding":[
        ("/api/futures/funding-rate/exchange-list",{"symbol":coin}),
      ],
      "taker":[
        ("/api/futures/taker-buy-sell-volume/exchange-list",{"symbol":coin,"range":"4h"}),
        ("/api/futures/taker-buy-sell-volume/exchange-list",{"symbol":coin,"range":"1h"}),
        ("/api/futures/aggregated-taker-buy-sell-volume/history",{"symbol":coin,"interval":"4h","limit":6}),
      ],
      "ls":[
        ("/api/futures/global-long-short-account-ratio/history",{"exchange":"Binance","symbol":pair,"interval":"4h","limit":6}),
        ("/api/futures/global-long-short-account-ratio/history",{"exchange":"Binance","symbol":pair,"interval":"1h","limit":6}),
        ("/api/futures/global-long-short-account-ratio/history",{"exchange":"Binance","symbol":pair,"interval":"1d","limit":3}),
      ],
      "liquidation":[
        ("/api/futures/liquidation/exchange-list",{"symbol":coin}),
        ("/api/futures/liquidation/aggregated-history",{"symbol":coin,"interval":"4h","limit":6}),
        ("/api/futures/liquidation/history",{"exchange":"Binance","symbol":pair,"interval":"4h","limit":6}),
      ],
      "top_account":[
        ("/api/futures/top-long-short-account-ratio/history",{"exchange":"Binance","symbol":pair,"interval":"4h","limit":6}),
      ],
      "top_position":[
        ("/api/futures/top-long-short-position-ratio/history",{"exchange":"Binance","symbol":pair,"interval":"4h","limit":6}),
      ],
      "basis":[
        ("/api/futures/basis/history",{"exchange":"Binance","symbol":pair,"interval":"4h","limit":6}),
      ],
    }
    for name,variants in specs.items():
        data,meta=_cg_request_variants(name,coin,variants,force=force)
        out[name]=data; out["meta"][name]=meta
        if not meta.get("ok"):out["errors"][name]=" | ".join(meta.get("errors",[]))[:260]

    if isinstance(out["oi"],list):
        out["oi"]=next((x for x in out["oi"] if str(x.get("exchange","")).lower()=="all"),out["oi"][0] if out["oi"] else None)
    return out

def v45_fmt_num(v):
    try:
        n=float(v)
        if abs(n)>=1e9:return f"{n/1e9:.2f}B"
        if abs(n)>=1e6:return f"{n/1e6:.2f}M"
        if abs(n)>=1e3:return f"{n/1e3:.2f}K"
        return f"{n:.4f}"
    except Exception:return "N/A"

