        ("auto", auto_cmd), ("god", god_cmd), ("real", real_cmd), ("scalp", scalp_cmd),
        ("tenx", tenx_cmd), ("breakout", breakout_cmd), ("bottom", bottom_cmd),
        ("timing", timing_cmd), ("now", now_cmd), ("win", win_cmd),
        ("smart", smart_cmd), ("danger", danger_cmd), ("watch", watch_cmd),
